# ================================================================ #
#  v8.10: Vision 端点 - 框选分析 + 星点叠加
# ================================================================ #

import base64
import io
import cv2
import numpy as np
from pydantic import BaseModel as PydanticBase


class RegionAnalyzeRequest(PydanticBase):
    """框选区域分析请求。"""
    image_base64: str  # 裁剪区域的 base64 图像
    action: str = "both"  # whitebalance / focus / both


class StackStartRequest(PydanticBase):
    """叠加开始请求。"""
    total_exposure: float  # 总曝光时长(秒)
    frame_exposure_ms: int = 100  # 单帧曝光(毫秒)


# 全局叠加引擎实例
_stack_engine = None
_stack_task = None


def _get_stack_engine():
    """获取或创建叠加引擎。"""
    global _stack_engine
    if _stack_engine is not None:
        return _stack_engine
    from src.vision.stack_engine import StackEngine
    _stack_engine = StackEngine(None)  # client 在实际使用时注入
    return _stack_engine


def _decode_image(b64: str) -> np.ndarray:
    """base64 → BGR numpy array。"""
    # 去掉可能的 data:image/...;base64, 前缀
    if ',' in b64:
        b64 = b64.split(',', 1)[1]
    data = base64.b64decode(b64)
    arr = np.frombuffer(data, np.uint8)
    return cv2.imdecode(arr, cv2.IMREAD_COLOR)


@api_router.post("/vision/region-analyze", summary="框选区域分析", tags=["Vision"])
async def region_analyze(req: RegionAnalyzeRequest) -> dict:
    """分析框选区域: 白平衡修正量 + 反差对焦。

    输入: 裁剪区域的 base64 JPEG 图像
    返回: 白平衡建议值 + 反差值
    """
    from src.vision.region_analyzer import analyze_whitebalance, calc_contrast

    try:
        bgr = _decode_image(req.image_base64)
        if bgr is None or bgr.size == 0:
            return {"success": False, "message": "图像解码失败"}
    except Exception as e:
        return {"success": False, "message": f"图像解码异常: {e}"}

    result = {"success": True}

    if req.action in ("whitebalance", "both"):
        wb = analyze_whitebalance(bgr)
        result["whitebalance"] = wb

    if req.action in ("focus", "both"):
        contrast = calc_contrast(bgr)
        result["contrast"] = round(contrast, 2)

    return result


@api_router.post("/vision/whitebalance-apply", summary="应用白平衡修正", tags=["Vision"])
async def whitebalance_apply(data: dict) -> dict:
    """将计算出的白平衡值写入 ISAPI。

    输入: {"device_id": str, "red_gain": int, "blue_gain": int}
    """
    import xml.etree.ElementTree as ET
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZ控制器未初始化"}

    device_id = data.get("device_id", "")
    red = int(data.get("red_gain", 100))
    blue = int(data.get("blue_gain", 100))

    controller = mgr.get_controller(device_id)
    if not controller:
        return {"success": False, "message": f"设备未连接: {device_id}"}

    client = controller.client

    # 读当前模式
    try:
        resp = client.get("/Image/channels/1/whiteBalance")
        current_mode = "manual"
        if resp.status_code == 200:
            root = ET.fromstring(resp.xml)
            for elem in root.iter():
                tag = elem.tag.split('}')[-1] if '}' in elem.tag else elem.tag
                if tag == "WhiteBalanceStyle":
                    current_mode = (elem.text or "manual").lower()

        xml_str = f'''<?xml version="1.0" encoding="UTF-8"?>
<WhiteBalance version="2.0" xmlns="http://www.hikvision.com/ver20/XMLSchema">
<WhiteBalanceStyle>manual</WhiteBalanceStyle>
<WhiteBalanceRed>{red}</WhiteBalanceRed>
<WhiteBalanceBlue>{blue}</WhiteBalanceBlue>
</WhiteBalance>'''

        put_resp = client.put("/Image/channels/1/whiteBalance", xml_str)
        if put_resp.status_code == 200:
            return {"success": True, "message": "白平衡已更新",
                    "data": {"mode": "manual", "red_gain": red, "blue_gain": blue}}
        return {"success": False, "message": f"写入失败: HTTP {put_resp.status_code}"}
    except Exception as e:
        return {"success": False, "message": f"白平衡写入异常: {e}"}


@api_router.post("/vision/focus-search", summary="反差对焦搜索", tags=["Vision"])
async def focus_search(data: dict) -> dict:
    """基于框选区域执行反差对焦搜索。

    输入: {"device_id": str, "image_base64": str}
    返回: 搜索结果 + 最终反差值
    """
    from src.vision.region_analyzer import ContrastAF, calc_contrast

    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZ控制器未初始化"}

    device_id = data.get("device_id", "")
    controller = mgr.get_controller(device_id)
    if not controller:
        return {"success": False, "message": f"设备未连接: {device_id}"}

    client = controller.client
    af = ContrastAF(step_size=5, min_step=1)

    try:
        bgr = _decode_image(data["image_base64"])
        if bgr is None:
            return {"success": False, "message": "图像解码失败"}
    except Exception as e:
        return {"success": False, "message": f"图像解码异常: {e}"}

    # 对焦搜索循环 (最多 20 步)
    steps_log = []
    for i in range(20):
        cmd = af.step(bgr)
        steps_log.append({"step": i, "contrast": cmd["contrast"],
                           "action": cmd["action"], "message": cmd["message"]})

        if cmd["action"] == "stop":
            break

        # 执行对焦移动
        speed = cmd["step"]
        if cmd["action"] == "focus_far":
            controller.focus_move_continuous(speed)
        else:
            controller.focus_move_continuous(-speed)

        time.sleep(0.3)
        controller.stop_move()
        time.sleep(0.2)

        # 截下一帧
        try:
            pic_resp = client.get("/Streaming/channels/1/picture")
            if pic_resp.status_code == 200:
                arr = np.frombuffer(pic_resp.raw_bytes if hasattr(pic_resp, 'raw_bytes') else b'', np.uint8)
                bgr = cv2.imdecode(arr, cv2.IMREAD_COLOR)
                if bgr is None:
                    break
            else:
                break
        except Exception:
            break

    final_contrast = calc_contrast(bgr) if bgr is not None else 0
    return {
        "success": True,
        "steps": steps_log,
        "final_contrast": round(final_contrast, 2),
        "total_steps": len(steps_log),
    }


@api_router.post("/vision/stack-start", summary="启动星点叠加", tags=["Vision"])
async def stack_start(req: StackStartRequest) -> dict:
    """启动星点叠加会话。"""
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZ控制器未初始化"}

    active = mgr.get_active_device()
    if not active:
        return {"success": False, "message": "无活跃设备"}

    total_frames = int(req.total_exposure * 1000 / req.frame_exposure_ms)
    if total_frames < 2:
        return {"success": False, "message": f"总帧数太少: {total_frames}"}

    from src.vision.stack_engine import StackEngine
    global _stack_engine, _stack_task

    controller = mgr.get_controller(active["device_id"])
    _stack_engine = StackEngine(controller.client if controller else None)
    _stack_engine.start(total_frames)

    # 启动后台采集任务
    import asyncio
    _stack_task = asyncio.create_task(_run_stack_collection(
        mgr, active["device_id"], req.frame_exposure_ms, total_frames))

    return {
        "success": True,
        "total_frames": total_frames,
        "frame_exposure_ms": req.frame_exposure_ms,
        "total_exposure_s": req.total_exposure,
    }


async def _run_stack_collection(mgr, device_id: str, exposure_ms: int, total_frames: int):
    """后台帧采集循环。"""
    global _stack_engine, _stack_task
    from src.core.ws_manager import WebSocketManager

    controller = mgr.get_controller(device_id)
    if not controller or not _stack_engine:
        return

    client = controller.client
    ws_mgr = WebSocketManager()

    for i in range(total_frames):
        if not _stack_engine._running or _stack_engine._cancelled:
            break

        try:
            pic_resp = client.get("/Streaming/channels/1/picture")
            if pic_resp.status_code != 200:
                continue
            arr = np.frombuffer(pic_resp.raw_bytes if hasattr(pic_resp, 'raw_bytes') else b'', np.uint8)
            bgr = cv2.imdecode(arr, cv2.IMREAD_COLOR)
            if bgr is None:
                continue

            result = _stack_engine.add_frame(bgr)
            if result and result.get("preview_jpg_base64"):
                # 推送预览到 WebSocket
                await ws_mgr.broadcast_json({
                    "type": "stack_preview",
                    "frame": result["index"],
                    "total": total_frames,
                    "image": result["preview_jpg_base64"],
                })
        except Exception:
            continue

        await asyncio.sleep(exposure_ms / 1000.0)

    # 完成
    if _stack_engine:
        final = _stack_engine.finish()
        await ws_mgr.broadcast_json({
            "type": "stack_complete",
            **final,
        })


@api_router.post("/vision/stack-stop", summary="停止星点叠加", tags=["Vision"])
async def stack_stop() -> dict:
    """停止叠加并返回结果。"""
    global _stack_engine, _stack_task
    if _stack_engine:
        result = _stack_engine.finish()
        _stack_engine = None
        _stack_task = None
        return result
    return {"success": False, "message": "无活跃叠加会话"}


@api_router.post("/vision/stack-cancel", summary="取消星点叠加", tags=["Vision"])
async def stack_cancel() -> dict:
    """取消叠加。"""
    global _stack_engine, _stack_task
    if _stack_engine:
        _stack_engine.cancel()
        _stack_engine = None
        _stack_task = None
        return {"success": True, "message": "已取消"}
    return {"success": False, "message": "无活跃叠加会话"}

