    _regionMode = mode;
    btnWB.className = mode === 'whitebalance' ? 'btn btn-primary btn-sm' : 'btn btn-secondary btn-sm';
    btnAF.className = mode === 'focus' ? 'btn btn-primary btn-sm' : 'btn btn-secondary btn-sm';
    overlay.style.display = 'block';
    box.style.display = 'none';
}

function _getOverlayPos(e) {
    var overlay = document.getElementById('regionOverlay');
    var rect = overlay.getBoundingClientRect();
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
}

function _finishRegion() {
    var overlay = document.getElementById('regionOverlay');
    var box = document.getElementById('regionBox');
    var btnWB = document.getElementById('btnRegionWB');
    var btnAF = document.getElementById('btnRegionAF');
    var canvas = document.querySelector('#divPlugin canvas');
    if (!canvas) { showToast('error', '未找到视频画面'); return; }

    // 截取框选区域
    var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
    var cw = canvas.width, ch = canvas.height;
    var sx = parseInt(box.style.left) / ow * cw;
    var sy = parseInt(box.style.top) / oh * ch;
    var sw = parseInt(box.style.width) / ow * cw;
    var sh = parseInt(box.style.height) / oh * ch;
    if (sw < 5 || sh < 5) { showToast('warning', '框选区域太小'); return; }

    var tmp = document.createElement('canvas');
    tmp.width = sw; tmp.height = sh;
    tmp.getContext('2d').drawImage(canvas, sx, sy, sw, sh, 0, 0, sw, sh);
    var b64 = tmp.toDataURL('image/jpeg', 0.85);

    var deviceId = window.connectedDevice.ip;
    if (_regionMode === 'whitebalance') {
        apiPost('/api/v1/vision/region-analyze', { image_base64: b64, action: 'whitebalance' })
            .then(function(r) {
                if (!r || !r.success) { showToast('error', '分析失败'); return; }
                var wb = r.whitebalance;
                apiPost('/api/v1/vision/whitebalance-apply', {
                    device_id: deviceId, red_gain: wb.red_gain, blue_gain: wb.blue_gain
                }).then(function(r2) {
                    showToast(r2.success ? 'success' : 'error',
                        r2.success ? '白平衡已应用 R=' + wb.red_gain + ' B=' + wb.blue_gain : r2.message);
                });
            }).catch(function(e) { showToast('error', '异常: ' + e.message); });
    } else if (_regionMode === 'focus') {
        showToast('info', '反差对焦中...');
        apiPost('/api/v1/vision/focus-search', { device_id: deviceId, image_base64: b64 })
            .then(function(r) {
                showToast(r.success ? 'success' : 'error',
                    r.success ? '对焦完成 (' + r.total_steps + '步, 反差=' + r.final_contrast + ')' : r.message);
            }).catch(function(e) { showToast('error', '异常: ' + e.message); });
    }

    // 恢复按钮状态
    _regionMode = null;
    btnWB.className = 'btn btn-secondary btn-sm';
    btnAF.className = 'btn btn-secondary btn-sm';
    overlay.style.display = 'none';
    box.style.display = 'none';
}

(function() {
    var overlay = document.getElementById('regionOverlay');
    if (!overlay) return;
    var box = document.getElementById('regionBox');
    var isDragging = false;
    overlay.addEventListener('mousedown', function(e) {
        if (!_regionMode) return;
        var pos = _getOverlayPos(e);
        _regionStartX = pos.x; _regionStartY = pos.y;
        box.style.left = pos.x + 'px'; box.style.top = pos.y + 'px';
        box.style.width = '0px'; box.style.height = '0px';
        box.style.display = 'block';
        isDragging = true;
        e.preventDefault();
    });
    overlay.addEventListener('mousemove', function(e) {
        if (!isDragging || !_regionMode) return;
        var pos = _getOverlayPos(e);
        var x = Math.min(_regionStartX, pos.x);
        var y = Math.min(_regionStartY, pos.y);
        var w = Math.abs(pos.x - _regionStartX);
        var h = Math.abs(pos.y - _regionStartY);
        box.style.left = x + 'px'; box.style.top = y + 'px';
        box.style.width = w + 'px'; box.style.height = h + 'px';
    });
    overlay.addEventListener('mouseup', function(e) {
        if (!isDragging || !_regionMode) return;
        isDragging = false;
        _finishRegion();
    });
    overlay.addEventListener('mouseleave', function() {
        if (isDragging) { isDragging = false; _finishRegion(); }
    });
})();

</script>

