import ast
router_code = open('src/api/router.py', encoding='utf-8').read()
tree = ast.parse(router_code)
vision_routes = []
for node in ast.walk(tree):
    if not isinstance(node, ast.Call):
        continue
    if not (hasattr(node.func, 'attr') and node.func.attr in ('get', 'post', 'put', 'delete')):
        continue
    for kw in node.keywords:
        if kw.arg == 'path' and isinstance(kw.value, ast.Constant) and 'vision' in str(kw.value.value):
            vision_routes.append((node.func.attr.upper(), kw.value.value))
print(f'[OK] vision routes: {len(vision_routes)}')
for method, path in vision_routes:
    print(f'  {method} {path}')

