function _finishRegionViaApi() {
    var dev = window.connectedDevice;
    if (!dev || !dev.ip) { showToast('error', '未连接设备'); return; }
    var overlay = document.getElementById('regionOverlay');
    var box = document.getElementById('regionBox');
    showToast('info', '正在截图分析...');
    apiPost('/api/v1/ptz/' + dev.ip + '/capture', null).then(function(r) {
        if (!r || !r.success) { showToast('error', '截图失败'); return; }
        var imgPath = r.data.image_path;
        var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
        var sx = parseInt(box.style.left) / ow;
        var sy = parseInt(box.style.top) / oh;
        var sw = parseInt(box.style.width) / ow;
        var sh = parseInt(box.style.height) / oh;
        if (sw < 0.01 || sh < 0.01) { showToast('warning', '框选区域太小'); return; }
        var payload = { image_path: imgPath, x: sx, y: sy, w: sw, h: sh };
        apiPost('/api/v1/vision/region-analyze', {
            image_path: imgPath, x: sx, y: sy, w: sw, h: sh, action: _regionMode
        }).then(function(r2) {
            _resetRegionUI();
            if (!r2 || !r2.success) { showToast('error', '分析失败'); return; }
            if (_regionMode === 'whitebalance' && r2.whitebalance) {
                var wb = r2.whitebalance;
                apiPost('/api/v1/vision/whitebalance-apply', {
                    device_id: dev.ip, red_gain: wb.red_gain, blue_gain: wb.blue_gain
                }).then(function(r3) {
                    showToast(r3.success ? 'success' : 'error',
                        r3.success ? '白平衡已应用 R=' + wb.red_gain + ' B=' + wb.blue_gain : r3.message);
                });
            } else {
                showToast('success', '对焦完成, 反差=' + (r2.contrast || '?'));
            }
        }).catch(function(e) { _resetRegionUI(); showToast('error', '异常: ' + e.message); });
    }).catch(function(e) { showToast('error', '截图异常: ' + e.message); });
}

