# ── v8.11: ISAPI 截图 → 后端裁剪 → 迭代搜索 ──────────────

_TEMP_ROOT = os.path.join(os.path.dirname(os.path.dirname(os.path.dirname(__file__))), "temp")


def _temp_dir(category: str, device_ip: str) -> str:
    """获取临时目录并确保存在。"""
    d = os.path.join(_TEMP_ROOT, category, device_ip.replace(".", "_"))
    os.makedirs(d, exist_ok=True)
    return d


def _cleanup_temp(category: str, device_ip: str):
    """清理指定设备指定类别的临时文件。"""
    import shutil
    d = os.path.join(_TEMP_ROOT, category, device_ip.replace(".", "_"))
    if os.path.exists(d):
        shutil.rmtree(d, ignore_errors=True)


def _capture_and_crop(client, mgr, device_ip: str, category: str,
                      x: float, y: float, w: float, h: float) -> tuple:
    """ISAPI 截图 → 按比例裁剪 → 返回 (bgr, 截图路径, 裁剪信息dict)。

    统一入口，白平衡和对焦共用。
    """
    import time as _time
    _time.sleep(0.1)  # 等设备稳定
    jpg = client.capture_picture()
    if not jpg:
        return None, "", {"error": "ISAPI截图失败"}

    # 保存全图
    ts = int(_time.time() * 1000)
    temp_dir = _temp_dir(category, device_ip)
    full_path = os.path.join(temp_dir, f"full_{ts}.jpg")
    with open(full_path, "wb") as f:
        f.write(jpg)

    bgr = cv2.imdecode(np.frombuffer(jpg, np.uint8), cv2.IMREAD_COLOR)
    if bgr is None:
        return None, full_path, {"error": "图像解码失败"}

    full_h, full_w = bgr.shape[:2]

    # 裁剪
    if w > 0 and h > 0:
        x1 = max(0, int(x * full_w))
        y1 = max(0, int(y * full_h))
        x2 = min(full_w, int((x + w) * full_w))
        y2 = min(full_h, int((y + h) * full_h))
        if x2 <= x1 or y2 <= y1:
            return bgr, full_path, {"error": "裁剪区域无效"}
        cropped = bgr[y1:y2, x1:x2]
        crop_path = os.path.join(temp_dir, f"crop_{ts}.jpg")
        cv2.imwrite(crop_path, cropped)
    else:
        cropped = bgr
        crop_path = full_path
        x1, y1, x2, y2 = 0, 0, full_w, full_h

    info = {
        "full_w": full_w, "full_h": full_h,
        "crop_x1": x1, "crop_y1": y1, "crop_x2": x2, "crop_y2": y2,
        "crop_w": x2 - x1, "crop_h": y2 - y1,
        "crop_path": crop_path,
        "pixels": (x2 - x1) * (y2 - y1),
    }
    return cropped, crop_path, info


def _apply_whitebalance(client, red: int, blue: int) -> dict:
    """写入白平衡到 ISAPI。"""
    xml_str = f'''<?xml version="1.0" encoding="UTF-8"?>
<WhiteBalance version="2.0" xmlns="http://www.hikvision.com/ver20/XMLSchema">
<WhiteBalanceStyle>manual</WhiteBalanceStyle>
<WhiteBalanceRed>{red}</WhiteBalanceRed>
<WhiteBalanceBlue>{blue}</WhiteBalanceBlue>
</WhiteBalance>'''
    resp = client.put("/Image/channels/1/whiteBalance", xml_str)
    return {"success": resp.status_code == 200, "status": resp.status_code}


@api_router.post("/vision/region-analyze", summary="框选区域分析（单次）", tags=["Vision"])
async def region_analyze(req: RegionAnalyzeRequest) -> dict:
    """单次框选分析：裁剪 + RGB统计 + 反差。用于预览。"""
    from src.vision.region_analyzer import _rgb_stats, calc_contrast

    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZ控制器未初始化"}

    connected = mgr.get_connected_device()
    if not connected:
        return {"success": False, "message": "无活跃设备"}

    device_ip = connected["ip"]
    client, err = _get_client_for_device(mgr, device_ip)
    if err:
        return {"success": False, "message": err}

    bgr, crop_path, info = _capture_and_crop(client, mgr, device_ip, "WB",
                                              req.x, req.y, req.w, req.h)
    if bgr is None:
        return {"success": False, "message": info.get("error", "截图失败")}

    stats = _rgb_stats(bgr)
    contrast = calc_contrast(bgr)
    return {"success": True, "crop": info, "rgb": stats, "contrast": round(contrast, 2)}


@api_router.post("/vision/whitebalance-search", summary="白平衡迭代搜索", tags=["Vision"])
async def whitebalance_search(data: dict) -> dict:
    """白平衡迭代搜索。
    请求: {"x":0.1,"y":0.1,"w":0.3,"h":0.3}
    响应: 每步迭代日志 + 最终 R/B 增益值。
    """
    from src.vision.region_analyzer import IterativeWB

    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZ控制器未初始化"}

    connected = mgr.get_connected_device()
    if not connected:
        return {"success": False, "message": "无活跃设备"}

    device_ip = connected["ip"]
    client, err = _get_client_for_device(mgr, device_ip)
    if err:
        return {"success": False, "message": err}

    x = float(data.get("x", 0))
    y = float(data.get("y", 0))
    w = float(data.get("w", 0))
    h = float(data.get("h", 0))

    if w <= 0 or h <= 0:
        return {"success": False, "message": "框选区域无效"}

    # 初始截图+裁剪
    bgr, crop_path, info = _capture_and_crop(client, mgr, device_ip, "WB", x, y, w, h)
    if bgr is None:
        return {"success": False, "message": info.get("error", "截图失败")}

    wb = IterativeWB()
    steps_log = [{"step": 0, "type": "start",
                   "crop": f"X={info['crop_x1']}~{info['crop_x2']}, Y={info['crop_y1']}~{info['crop_y2']}, 共{info['pixels']}像素"}]

    max_iter = 30
    for i in range(max_iter):
        cmd = wb.step(bgr)
        step_info = {
            "step": i + 1,
            "type": "wb",
            "stage": cmd["stage"],
            "step_size": cmd["step_size"],
            "red_gain": cmd["red_gain"],
            "blue_gain": cmd["blue_gain"],
            "r_avg": cmd["r_avg"],
            "g_avg": cmd["g_avg"],
            "b_avg": cmd["b_avg"],
            "delta": cmd["delta"],
            "message": cmd["message"],
        }
        steps_log.append(step_info)

        if cmd["action"] == "stop":
            break

        # 应用增益到设备
        _apply_whitebalance(client, cmd["red_gain"], cmd["blue_gain"])
        time.sleep(0.15)

        # 重新截图+裁剪
        bgr, crop_path, _ = _capture_and_crop(client, mgr, device_ip, "WB", x, y, w, h)
        if bgr is None:
            steps_log.append({"step": i + 1, "type": "error", "message": "截图失败"})
            break

    # 清理
    _cleanup_temp("WB", device_ip)
    steps_log.append({"step": len(steps_log), "type": "cleanup", "message": "清理完成"})

    last_wb = steps_log[-2] if len(steps_log) >= 2 else {}
    return {"success": True, "steps": steps_log,
            "final_red": last_wb.get("red_gain", 100),
            "final_blue": last_wb.get("blue_gain", 100),
            "total_steps": len(steps_log)}


@api_router.post("/vision/focus-search", summary="反差对焦搜索", tags=["Vision"])
async def focus_search(data: dict) -> dict:
    """反差对焦迭代搜索（时间基: 0.5s→0.2s→0.1s）。
    请求: {"x":0.1,"y":0.1,"w":0.3,"h":0.3}
    """
    from src.vision.region_analyzer import ContrastAF, calc_contrast

    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZ控制器未初始化"}

    connected = mgr.get_connected_device()
    if not connected:
        return {"success": False, "message": "无活跃设备"}

    device_ip = connected["ip"]
    client, err = _get_client_for_device(mgr, device_ip)
    if err:
        return {"success": False, "message": err}

    x = float(data.get("x", 0))
    y = float(data.get("y", 0))
    w = float(data.get("w", 0))
    h = float(data.get("h", 0))

    if w <= 0 or h <= 0:
        return {"success": False, "message": "框选区域无效"}

    # 初始截图+裁剪
    bgr, crop_path, info = _capture_and_crop(client, mgr, device_ip, "Focus", x, y, w, h)
    if bgr is None:
        return {"success": False, "message": info.get("error", "截图失败")}

    af = ContrastAF()
    steps_log = [{"step": 0, "type": "start",
                   "crop": f"X={info['crop_x1']}~{info['crop_x2']}, Y={info['crop_y1']}~{info['crop_y2']}, 共{info['pixels']}像素"}]

    max_iter = 30
    for i in range(max_iter):
        cmd = af.step(bgr)
        step_info = {
            "step": i + 1,
            "type": "focus",
            "action": cmd["action"],
            "contrast": cmd["contrast"],
            "duration": cmd["duration"],
            "message": cmd["message"],
        }
        steps_log.append(step_info)

        if cmd["action"] == "stop":
            break

        # 驱动设备对焦 (按下→等待→松开)
        direction = "focus-far" if cmd["action"] == "focus_far" else "focus-near"
        mgr.ptz_move(device_ip, direction=direction, speed=60)
        time.sleep(cmd["duration"])
        mgr.ptz_stop(device_ip)
        time.sleep(0.15)

        # 重新截图+裁剪
        bgr, crop_path, _ = _capture_and_crop(client, mgr, device_ip, "Focus", x, y, w, h)
        if bgr is None:
            steps_log.append({"step": i + 1, "type": "error", "message": "截图失败"})
            break

    # 清理
    _cleanup_temp("Focus", device_ip)
    steps_log.append({"step": len(steps_log), "type": "cleanup", "message": "清理完成"})

    final_contrast = calc_contrast(bgr) if bgr is not None else 0
    return {"success": True, "steps": steps_log,
            "final_contrast": round(final_contrast, 2), "total_steps": len(steps_log)}

