// v8.11: 统一 ISAPI 截图 → 后端裁剪 → 迭代搜索 → 操作日志
function _finishRegion() {
    var overlay = document.getElementById('regionOverlay');
    var box = document.getElementById('regionBox');
    var dev = window.connectedDevice;
    if (!dev || !dev.ip) { showToast('error', '未连接设备'); _resetRegionUI(); return; }

    var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
    var sx = parseInt(box.style.left) / ow;
    var sy = parseInt(box.style.top) / oh;
    var sw = parseInt(box.style.width) / ow;
    var sh = parseInt(box.style.height) / oh;
    if (sw < 0.01 || sh < 0.01) { showToast('warning', '框选区域太小'); _resetRegionUI(); return; }

    var mode = _regionMode;
    var endpoint = mode === 'whitebalance' ? '/api/v1/vision/whitebalance-search'
                                           : '/api/v1/vision/focus-search';
    var label = mode === 'whitebalance' ? '白平衡' : '对焦';

    _resetRegionUI();
    showToast('info', label + '迭代中...');
    addLog('info', '── ' + label + '迭代开始 ──');

    apiPost(endpoint, { x: sx, y: sy, w: sw, h: sh }).then(function(r) {
        if (!r || !r.success) {
            addLog('error', label + '失败: ' + (r ? r.message : '未知错误'));
            showToast('error', label + '失败');
            return;
        }
        // 显示每一步
        var steps = r.steps || [];
        for (var i = 0; i < steps.length; i++) {
            var s = steps[i];
            if (s.type === 'start') {
                addLog('info', label + '开始, ' + s.crop);
            } else if (s.type === 'wb') {
                addLog('info', '调整' + label + ' #' + s.step + ': ' + s.stage
                    + ' R=' + s.red_gain + ' B=' + s.blue_gain
                    + ' → R=' + s.r_avg + ' G=' + s.g_avg + ' B=' + s.b_avg
                    + ' (delta=' + s.delta + ')');
            } else if (s.type === 'focus') {
                var dur = s.duration ? s.duration.toFixed(2) + 's' : '-';
                addLog('info', '对焦 #' + s.step + ': ' + s.action
                    + ' 持续=' + dur + ' 反差=' + s.contrast
                    + ' [' + s.message + ']');
            } else if (s.type === 'cleanup') {
                addLog('info', '执行清理... ' + s.message);
            }
        }
        if (mode === 'whitebalance') {
            showToast('success', '白平衡完成 R=' + r.final_red + ' B=' + r.final_blue);
            addLog('success', '── 白平衡完成: R=' + r.final_red + ' B=' + r.final_blue + ' (' + r.total_steps + '步) ──');
        } else {
            showToast('success', '对焦完成 反差=' + r.final_contrast + ' (' + r.total_steps + '步)');
            addLog('success', '── 对焦完成: 反差=' + r.final_contrast + ' (' + r.total_steps + '步) ──');
        }
    }).catch(function(e) {
        addLog('error', label + '异常: ' + e.message);
        showToast('error', '异常: ' + e.message);
    });
}

