    if not connected:
        return {"success": False, "message": "无活跃设备"}

    device_ip = connected["ip"]
    client, err = _get_client_for_device(mgr, device_ip)
    if err:
        return {"success": False, "message": err}

    x = float(data.get("x", 0))
    y = float(data.get("y", 0))
    w = float(data.get("w", 0))
    h = float(data.get("h", 0))

    if w <= 0 or h <= 0:
        return {"success": False, "message": "框选区域无效"}

    # 初始截图+裁剪
    bgr, crop_path, info = _capture_and_crop(client, mgr, device_ip, "Focus", x, y, w, h)
    if bgr is None:
        return {"success": False, "message": info.get("error", "截图失败")}

    af = ContrastAF()
    steps_log = [{"step": 0, "type": "start",
                   "crop": f"X={info['crop_x1']}~{info['crop_x2']}, Y={info['crop_y1']}~{info['crop_y2']}, 共{info['pixels']}像素"}]

    max_iter = 30
    for i in range(max_iter):
        cmd = af.step(bgr)
        step_info = {
            "step": i + 1,
            "type": "focus",
            "action": cmd["action"],
            "contrast": cmd["contrast"],
            "duration": cmd["duration"],
            "message": cmd["message"],
        }
        steps_log.append(step_info)

        if cmd["action"] == "stop":
            break

        # 驱动设备对焦 (按下→等待→松开)
        direction = "focus-far" if cmd["action"] == "focus_far" else "focus-near"
        mgr.ptz_move(device_ip, direction=direction, speed=60)
        time.sleep(cmd["duration"])
        mgr.ptz_stop(device_ip)
        time.sleep(0.15)

        # 重新截图+裁剪
        bgr, crop_path, _ = _capture_and_crop(client, mgr, device_ip, "Focus", x, y, w, h)
        if bgr is None:
            steps_log.append({"step": i + 1, "type": "error", "message": "截图失败"})
            break

    # 清理
    _cleanup_temp("Focus", device_ip)
    steps_log.append({"step": len(steps_log), "type": "cleanup", "message": "清理完成"})

    final_contrast = calc_contrast(bgr) if bgr is not None else 0
    return {"success": True, "steps": steps_log,
            "final_contrast": round(final_contrast, 2), "total_steps": len(steps_log)}


